import { useEffect, useState } from "react";
import Navbar from "../components/Navbar";
import {
  getScores,
  addScore,
  getCharities,
  selectCharity,
  runDraw
} from "../services/api";

function Dashboard() {
  const [scores, setScores] = useState([]);
  const [score, setScore] = useState("");
  const [charities, setCharities] = useState([]);
  const [selected, setSelected] = useState("");
  const [result, setResult] = useState("");

  const token = localStorage.getItem("token");

  useEffect(() => {
    loadScores();
    loadCharities();
  }, []);

  const loadScores = async () => {
    const data = await getScores(token);
    setScores(data);
  };

  const loadCharities = async () => {
    const data = await getCharities();
    setCharities(data);
  };

  const handleAdd = async () => {
    await addScore(score, token);
    setScore("");
    loadScores();
  };

  const handleCharity = async () => {
    await selectCharity(selected, token);
    alert("Saved!");
  };

  const handleDraw = async () => {
    const data = await runDraw(token);
    setResult(`Draw: ${data.drawNumbers} | Matches: ${data.matches}`);
  };

  return (
    <>
      <Navbar />

      <div className="container">

        <div className="card">
          <h3>Add Score</h3>
          <input value={score} onChange={e => setScore(e.target.value)} />
          <button onClick={handleAdd}>Add</button>
        </div>

        <div className="card">
          <h3>Your Scores</h3>
          <ul>
            {scores.map((s, i) => (
              <li key={i}>{s.score}</li>
            ))}
          </ul>
        </div>

        <div className="card">
          <h3>Select Charity</h3>
          <select onChange={e => setSelected(e.target.value)}>
            <option>Select</option>
            {charities.map((c, i) => (
              <option key={i}>{c.name}</option>
            ))}
          </select>
          <button onClick={handleCharity}>Save</button>
        </div>

        <div className="card">
          <h3>Draw</h3>
          <button onClick={handleDraw}>Run Draw</button>
          <p>{result}</p>
        </div>

      </div>
    </>
  );
}

export default Dashboard;
